import React, { useState, useMemo } from 'react';

// ============================================
// Design Tokens
// ============================================
const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
  },
  font: "'JetBrains Mono', monospace",
};

const termColors = ['#f472b6', '#38bdf8', '#a3e635', '#fbbf24'];

// ============================================
// Determinant Calculation
// ============================================
function det3x3(m) {
  return (
    m[0][0] * (m[1][1] * m[2][2] - m[1][2] * m[2][1]) -
    m[0][1] * (m[1][0] * m[2][2] - m[1][2] * m[2][0]) +
    m[0][2] * (m[1][0] * m[2][1] - m[1][1] * m[2][0])
  );
}

function getMinor(matrix, skipRow, skipCol) {
  const minor = [];
  for (let i = 0; i < matrix.length; i++) {
    if (i === skipRow) continue;
    const row = [];
    for (let j = 0; j < matrix[i].length; j++) {
      if (j === skipCol) continue;
      row.push(matrix[i][j]);
    }
    minor.push(row);
  }
  return minor;
}

// ============================================
// Matrix Display with Highlighting
// ============================================
function MatrixDisplay({ matrix, highlightRow, highlightCol, crossedOut, small, color }) {
  const size = matrix.length;
  const cellSize = small ? '24px' : '34px';
  const fontSize = small ? '10px' : '12px';

  return (
    <div style={{
      display: 'inline-flex',
      alignItems: 'center',
      padding: small ? '4px' : '8px',
      background: color ? `${color}10` : theme.colors.surface,
      borderRadius: '8px',
      border: `1px solid ${color || theme.colors.border}40`,
    }}>
      <span style={{ color: color || theme.colors.textMuted, fontSize: small ? '18px' : '28px', fontWeight: '200' }}>[</span>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
        {matrix.map((row, i) => (
          <div key={i} style={{ display: 'flex', gap: '2px' }}>
            {row.map((val, j) => {
              const isCrossed = crossedOut && (i === highlightRow || j === highlightCol);
              const isHighlighted = !crossedOut && i === highlightRow && j === highlightCol;
              const isInMinor = crossedOut && i !== highlightRow && j !== highlightCol;

              return (
                <div
                  key={j}
                  style={{
                    width: cellSize,
                    height: cellSize,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize,
                    fontWeight: isHighlighted ? '700' : '500',
                    color: isCrossed ? theme.colors.textMuted : isHighlighted ? termColors[j] : theme.colors.text,
                    background: isHighlighted ? `${termColors[j]}30` : isInMinor ? `${theme.colors.primary}15` : 'transparent',
                    borderRadius: '4px',
                    textDecoration: isCrossed ? 'line-through' : 'none',
                    opacity: isCrossed ? 0.3 : 1,
                    transition: 'all 0.2s',
                  }}
                >
                  {val}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      <span style={{ color: color || theme.colors.textMuted, fontSize: small ? '18px' : '28px', fontWeight: '200' }}>]</span>
    </div>
  );
}

// ============================================
// Term Card
// ============================================
function TermCard({ element, sign, minorDet, col, isActive }) {
  const color = termColors[col];
  const result = sign * element * minorDet;

  return (
    <div style={{
      padding: '8px',
      background: isActive ? `${color}15` : theme.colors.surface,
      borderRadius: '6px',
      border: `1px solid ${isActive ? color : theme.colors.border}`,
      textAlign: 'center',
      opacity: isActive ? 1 : 0.4,
      transition: 'all 0.2s',
    }}>
      <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '2px' }}>
        Term {col + 1}
      </div>
      <div style={{ fontSize: '11px', color: theme.colors.textSecondary }}>
        <span style={{ color: sign > 0 ? theme.colors.positive : theme.colors.negative }}>{sign > 0 ? '+' : '-'}</span>
        <span style={{ color, fontWeight: '600' }}>{Math.abs(element)}</span>
        <span style={{ color: theme.colors.textMuted }}> x </span>
        <span>{minorDet}</span>
      </div>
      <div style={{ fontSize: '12px', fontWeight: '700', color, marginTop: '2px' }}>
        = {result}
      </div>
    </div>
  );
}

